def tar_filter(tarinfo):
    if os.path.islink(tarinfo.name):
        real_path = os.path.realpath(tarinfo.name)
        if not os.path.exists(real_path):
            print("Warning: Skipping broken symlink: {}".format(tarinfo.name))
